SELECT COUNT(*) AS active_account_count
FROM account_holders
WHERE status = 'Active';

SELECT COUNT(*) AS transaction_count
FROM account_activity
WHERE account_id = 1;

SELECT account_id, dividend_rate, apy
FROM interest_rates
WHERE is_variable = 0;

SELECT name
FROM customers
ORDER BY name ASC;

SELECT DISTINCT account_id
FROM account_activity
WHERE transaction_date = '2023-05-02';
